class Solution:
    def decodeCiphertext(self, encodedText, rows):
        n = len(encodedText)
        cols = n // rows if rows else 0
        if cols == 0:
            return ''
        grid = [list(encodedText[r * cols:(r + 1) * cols]) for r in range(rows)]
        buckets = [[] for _ in range(cols)]
        for r in range(rows):
            for c in range(cols):
                d = c - r
                if d >= 0:
                    buckets[d].append(grid[r][c])
        chars = []
        for d in range(cols):
            chars.extend(buckets[d])
        return ''.join(chars).rstrip()

