class Solution:
    def decodeCiphertext(self, encodedText: str, rows: int) -> str:
        n = len(encodedText)
        cols = n // rows if rows else 0
        if cols == 0:
            return ''
        res = []
        for d in range(cols):
            row, col = 0, d
            while row < rows and col < cols:
                res.append(encodedText[row * cols + col])
                row += 1
                col += 1
        return ''.join(res).rstrip()

